diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index 1ba548b6ff06..8624cc0d3819 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1153,6 +1153,7 @@ static bool MulWillOverflow(APInt &C0, APInt &C1, bool IsSigned) {
 // does not overflow.
 // Simplifies (X / C0) * C1 + (X % C0) * C2 to
 // (X / C0) * (C1 - C2 * C0) + X * C2
+
 Value *InstCombinerImpl::SimplifyAddWithRemainder(BinaryOperator &I) {
   Value *LHS = I.getOperand(0), *RHS = I.getOperand(1);
   Value *X, *MulOpV;
@@ -1180,6 +1181,22 @@ Value *InstCombinerImpl::SimplifyAddWithRemainder(BinaryOperator &I) {
     }
   }

+  // New pattern: (X % C0) + (X / C0) * C0 -> X
+  Value *RemV, *MulV;
+  APInt C;
+  bool RemIsSignedLocal;
+  if ((MatchRem(LHS, X, C, RemIsSignedLocal) && MatchMul(RHS, MulV, C)) ||
+      (MatchRem(RHS, X, C, RemIsSignedLocal) && MatchMul(LHS, MulV, C))) {
+    Value *DivV;
+    APInt DivC;
+    bool DivIsSignedLocal;
+    if (MatchDiv(MulV, DivV, DivC, DivIsSignedLocal) && X == DivV && C == DivC &&
+        RemIsSignedLocal == DivIsSignedLocal) {
+      // No overflow check needed because (X / C) * C + (X % C) = X exactly.
+      return X;
+    }
+  }
+
   // Match I = (X / C0) * C1 + (X % C0) * C2
   Value *Div, *Rem;
   APInt C1, C2;
@@ -1191,10 +1208,58 @@ Value *InstCombinerImpl::SimplifyAddWithRemainder(BinaryOperator &I) {
     std::swap(Div, Rem);
     std::swap(C1, C2);
   }
+  
+  // Helper to match division pattern (including bitwise)
+  auto MatchDivPattern = [&](Value *V, Value *&XOut, APInt &COut, bool &SignedOut) -> bool {
+    // Try explicit div instruction first
+    if (MatchDiv(V, XOut, COut, SignedOut))
+      return true;
+    
+    // Try bitwise unsigned division: X >> log2(C) where C is power of two
+    ConstantInt *ShiftCI;
+    if (match(V, m_LShr(m_Value(XOut), m_ConstantInt(ShiftCI)))) {
+      APInt ShiftAmt = ShiftCI->getValue();
+      if (ShiftAmt.isPowerOf2()) {
+        COut = APInt(ShiftAmt.getBitWidth(), 1) << ShiftAmt.getZExtValue();
+        SignedOut = false;
+        return true;
+      }
+    }
+    return false;
+  };
+  
+  // Helper to match remainder pattern (including bitwise)
+  auto MatchRemPattern = [&](Value *V, Value *&XOut, APInt &COut, bool &SignedOut) -> bool {
+    // Try explicit rem instruction first
+    if (MatchRem(V, XOut, COut, SignedOut))
+      return true;
+    
+    // Try bitwise unsigned remainder: X & (C-1) where C is power of two
+    ConstantInt *MaskCI;
+    if (match(V, m_And(m_Value(XOut), m_ConstantInt(MaskCI)))) {
+      APInt Mask = MaskCI->getValue();
+      if (Mask.isPowerOf2() && !Mask.isZero()) {
+        COut = Mask + 1;  // Convert mask to divisor
+        SignedOut = false;
+        return true;
+      }
+      // Also handle X & C where C+1 is power of two
+      APInt CPlusOne = Mask + 1;
+      if (CPlusOne.isPowerOf2() && !CPlusOne.isZero()) {
+        COut = CPlusOne;
+        SignedOut = false;
+        return true;
+      }
+    }
+    return false;
+  };
+  
   Value *DivOpV;
   APInt DivOpC;
-  if (MatchRem(Rem, X, C0, IsSigned) &&
-      MatchDiv(Div, DivOpV, DivOpC, IsSigned) && X == DivOpV && C0 == DivOpC) {
+  bool DivIsSignedLocal, RemIsSignedLocal2;
+  if (MatchRemPattern(Rem, X, C0, RemIsSignedLocal2) &&
+      MatchDivPattern(Div, DivOpV, DivOpC, DivIsSignedLocal) && 
+      X == DivOpV && C0 == DivOpC && RemIsSignedLocal2 == DivIsSignedLocal) {
     APInt NewC = C1 - C2 * C0;
     if (!NewC.isZero() && !Rem->hasOneUse())
       return nullptr;
@@ -1210,6 +1275,7 @@ Value *InstCombinerImpl::SimplifyAddWithRemainder(BinaryOperator &I) {
   return nullptr;
 }

+
 /// Fold
 ///   (1 << NBits) - 1
 /// Into:
